// Extract inputs
const category = $input.first().json.body.category;
const country = $input.first().json.body.country;
const companyName = $input.first().json.body.companyName || '';

// LinkedIn public search URL (for parsing)
const searchQuery = encodeURIComponent(`${category} ${companyName} ${country}`);

return [{
  json: {
    category,
    country,
    companyName,
    searchQuery
  }
}];

// Calculate ICP Score for LinkedIn leads
const lead = $input.first().json;
let score = 0;

if (lead.email && lead.email.length > 3) score += 20;
if (lead.phone && lead.phone.length > 5) score += 15;
if (lead.website && lead.website.length > 5) score += 15;
if (lead.isDecisionMaker) score += 20;
// LinkedIn leads get bonus for having title info
if (lead.title) score += 10;

lead.icp_score = score;
lead.status = score >= 60 ? 'qualified' : 'low_score';
lead.rating = 0; // LinkedIn doesn't have ratings

return [{ json: lead }];
